1	import { useEffect } from "react";
2	import { Link, useSearchParams } from "react-router-dom";
3	import { AccountPnlSection } from "@/features/analytics/AccountPnlSection";
4	import { AnalyticsFilters } from "@/features/analytics/AnalyticsFilters";
5	import { AnalyticsSummaryCards } from "@/features/analytics/AnalyticsSummaryCards";
6	import { PriceChart } from "@/features/analytics/PriceChart";
7	import { TraderLeaderboard } from "@/features/analytics/TraderLeaderboard";
8	import { VolumeChart } from "@/features/analytics/VolumeChart";
9	import { useSession } from "@/features/session/context";
10	import type { AnalyticsInterval, MarketSummary } from "@/lib/api/types";
11	import { useAccountPnl, useMarketAnalytics, useMarkets } from "@/lib/query/hooks";
12	import { ErrorMessage, LoadingPage } from "@/components/ui/Spinner";
13	
14	function isAnalyticsInterval(value: string | null): value is AnalyticsInterval {
15	  return value === "hour" || value === "day";
16	}
17	
18	function preferredMarket(markets: MarketSummary[]): MarketSummary | undefined {
19	  return markets.find((market) => market.status === "active") ?? markets[0];
20	}
21	
22	export default function Analytics() {
23	  const { session } = useSession();
24	  const marketsQuery = useMarkets();
25	  const pnlQuery = useAccountPnl(session.accountId);
26	  const [searchParams, setSearchParams] = useSearchParams();
27	
28	  const interval: AnalyticsInterval = isAnalyticsInterval(searchParams.get("interval")) ? (searchParams.get("interval") as AnalyticsInterval) : "day";
29	  const markets = marketsQuery.data?.markets ?? [];
30	  const selectedMarket = markets.find((market) => market.id === searchParams.get("market")) ?? preferredMarket(markets);
31	  const selectedMarketId = selectedMarket?.id ?? "";
32	  const analyticsQuery = useMarketAnalytics(selectedMarketId, {
33	    enabled: selectedMarketId.length > 0,
34	    interval,
35	  });
36	
37	  useEffect(() => {
38	    if (!selectedMarketId) {
39	      return;
40	    }
41	
42	    const next = new URLSearchParams(searchParams);
43	    let changed = false;
44	
45	    if (next.get("market") !== selectedMarketId) {
46	      next.set("market", selectedMarketId);
47	      changed = true;
48	    }
49	
50	    if (!isAnalyticsInterval(next.get("interval"))) {
51	      next.set("interval", interval);
52	      changed = true;
53	    }
54	
55	    if (changed) {
56	      setSearchParams(next, { replace: true });
57	    }
58	  }, [interval, searchParams, selectedMarketId, setSearchParams]);
59	
60	  if (marketsQuery.isLoading && markets.length === 0) {
61	    return <LoadingPage />;
62	  }
63	
64	  if (marketsQuery.error) {
65	    return <ErrorMessage message={marketsQuery.error instanceof Error ? marketsQuery.error.message : "Failed to load markets"} />;
66	  }
67	
68	  if (markets.length === 0) {
69	    return (
70	      <div style={emptyStateStyle}>
71	        No markets exist yet. Create a market before loading analytics.
72	        <div style={{ marginTop: "var(--space-sm)" }}>
73	          <Link to="/markets/new">Create a market</Link>
74	        </div>
75	      </div>
76	    );
77	  }
78	
79	  function updateParams(nextValues: { market?: string; interval?: AnalyticsInterval }) {
80	    const next = new URLSearchParams(searchParams);
81	    if (nextValues.market) {
82	      next.set("market", nextValues.market);
83	    }
84	    if (nextValues.interval) {
85	      next.set("interval", nextValues.interval);
86	    }
87	    setSearchParams(next);
88	  }
89	
90	  return (
91	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
92	      <div style={{ display: "grid", gap: "var(--space-xs)" }}>
93	        <h1 style={{ fontSize: "1.6rem", fontWeight: 600 }}>Market Analytics</h1>
94	        <p style={introStyle}>
95	          Track multi-outcome price history, accepted activity volume, top traders, and optional account mark-to-market from one top-level route.
96	        </p>
97	      </div>
98	
99	      <AnalyticsFilters
100	        markets={markets}
101	        selectedMarket={selectedMarket}
102	        selectedMarketId={selectedMarketId}
103	        interval={interval}
104	        onMarketChange={(marketId) => updateParams({ market: marketId })}
105	        onIntervalChange={(nextInterval) => updateParams({ interval: nextInterval })}
106	      />
107	
108	      {analyticsQuery.isLoading && !analyticsQuery.data && <LoadingPage />}
109	
110	      {analyticsQuery.error && (
111	        <ErrorMessage message={analyticsQuery.error instanceof Error ? analyticsQuery.error.message : "Failed to load analytics"} />
112	      )}
113	
114	      {analyticsQuery.data && (
115	        <>
116	          <AnalyticsSummaryCards summary={analyticsQuery.data.summary} />
117	          <PriceChart series={analyticsQuery.data.priceSeries} interval={interval} />
118	          <div style={{ display: "grid", gap: "var(--space-lg)", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", alignItems: "start" }}>
119	            <VolumeChart buckets={analyticsQuery.data.volumeBuckets} interval={interval} />
120	            <TraderLeaderboard rows={analyticsQuery.data.topTraders} />
121	          </div>
122	        </>
123	      )}
124	
125	      <AccountPnlSection
126	        accountId={session.accountId}
127	        selectedMarketId={selectedMarketId}
128	        data={pnlQuery.data}
129	        isLoading={pnlQuery.isLoading}
130	        error={pnlQuery.error}
131	      />
132	    </div>
133	  );
134	}
135	
136	const introStyle: React.CSSProperties = {
137	  color: "var(--color-text-muted)",
138	  maxWidth: 760,
139	};
140	
141	const emptyStateStyle: React.CSSProperties = {
142	  textAlign: "center",
143	  padding: "var(--space-xl)",
144	  color: "var(--color-text-muted)",
145	};
146

1	import { StatusBadge } from "@/components/ui/StatusBadge";
2	import { ErrorMessage, LoadingPage } from "@/components/ui/Spinner";
3	import type { AccountPnlResponse } from "@/lib/api/types";
4	import { formatCurrency } from "@/lib/utils/format";
5	import { formatSignedCurrency } from "./chartUtils";
6	
7	interface AccountPnlSectionProps {
8	  accountId: string;
9	  selectedMarketId: string;
10	  data?: AccountPnlResponse;
11	  isLoading: boolean;
12	  error: unknown;
13	}
14	
15	export function AccountPnlSection({
16	  accountId,
17	  selectedMarketId,
18	  data,
19	  isLoading,
20	  error,
21	}: AccountPnlSectionProps) {
22	  return (
23	    <section style={cardStyle}>
24	      <div style={{ marginBottom: "var(--space-md)" }}>
25	        <h2 style={titleStyle}>Account P&amp;L</h2>
26	        <p style={subtitleStyle}>Account-wide mark-to-market. Freshness can move when any market you hold reprices, even without a new trade from you.</p>
27	      </div>
28	
29	      {!accountId && (
30	        <div style={emptyStateStyle}>
31	          Set your Account ID in the header to load mark-to-market P&amp;L.
32	        </div>
33	      )}
34	
35	      {accountId && isLoading && <LoadingPage />}
36	
37	      {accountId && !isLoading && !!error && (
38	        <ErrorMessage message="Unable to load account P&L right now. Market analytics is still available." />
39	      )}
40	
41	      {accountId && !isLoading && !error && data && (
42	        <AccountPnlContent data={data} selectedMarketId={selectedMarketId} />
43	      )}
44	    </section>
45	  );
46	}
47	
48	function AccountPnlContent({
49	  data,
50	  selectedMarketId,
51	}: {
52	  data: AccountPnlResponse;
53	  selectedMarketId: string;
54	}) {
55	  const { pnl } = data.account;
56	  const selectedMarketPosition = pnl.positions.find((position) => position.marketId === selectedMarketId);
57	
58	  return (
59	    <div style={{ display: "grid", gap: "var(--space-md)" }}>
60	      <div style={{ display: "grid", gap: "var(--space-md)", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))" }}>
61	        <PnlMetricCard label="Cost Basis" value={formatCurrency(pnl.totals.costBasis)} />
62	        <PnlMetricCard label="Marked Value" value={formatCurrency(pnl.totals.markedValue)} />
63	        <PnlMetricCard label="Realized P&L" value={formatSignedCurrency(pnl.totals.realizedPnl)} accent={toneForValue(pnl.totals.realizedPnl)} />
64	        <PnlMetricCard label="Unrealized P&L" value={formatSignedCurrency(pnl.totals.unrealizedPnl)} accent={toneForValue(pnl.totals.unrealizedPnl)} />
65	        <PnlMetricCard label="Net P&L" value={formatSignedCurrency(pnl.totals.netPnl)} accent={toneForValue(pnl.totals.netPnl)} />
66	      </div>
67	
68	      <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
69	        Mark-to-market updated: {new Date(pnl.updatedAt).toLocaleString()}
70	      </div>
71	
72	      {selectedMarketPosition ? (
73	        <div style={selectedMarketCardStyle}>
74	          <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center", flexWrap: "wrap", marginBottom: "var(--space-sm)" }}>
75	            <div style={{ fontSize: "0.9rem", fontWeight: 600 }}>{selectedMarketPosition.marketTitle}</div>
76	            <StatusBadge status={selectedMarketPosition.marketStatus} />
77	          </div>
78	          <div style={{ display: "grid", gap: "var(--space-sm)", gridTemplateColumns: "repeat(auto-fit, minmax(130px, 1fr))" }}>
79	            <SelectedMetric label="Cost Basis" value={formatCurrency(selectedMarketPosition.costBasis)} />
80	            <SelectedMetric label="Marked Value" value={formatCurrency(selectedMarketPosition.markedValue)} />
81	            <SelectedMetric label="Realized" value={formatSignedCurrency(selectedMarketPosition.realizedPnl)} tone={toneForValue(selectedMarketPosition.realizedPnl)} />
82	            <SelectedMetric label="Unrealized" value={formatSignedCurrency(selectedMarketPosition.unrealizedPnl)} tone={toneForValue(selectedMarketPosition.unrealizedPnl)} />
83	          </div>
84	        </div>
85	      ) : (
86	        <div style={emptyStateStyle}>
87	          No recorded exposure in the selected market yet.
88	        </div>
89	      )}
90	
91	      {pnl.positions.length > 0 ? (
92	        <div style={tableShellStyle}>
93	          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.82rem" }}>
94	            <thead>
95	              <tr style={{ background: "var(--color-bg-hover)" }}>
96	                <th style={thStyle}>Market</th>
97	                <th style={thStyle}>Status</th>
98	                <th style={thStyle}>Cost Basis</th>
99	                <th style={thStyle}>Marked Value</th>
100	                <th style={thStyle}>Realized</th>
101	                <th style={thStyle}>Unrealized</th>
102	              </tr>
