88	                  textAnchor="end"
89	                >
90	                  {formatProbability(value)}
91	                </text>
92	              </g>
93	            );
94	          })}
95	
96	          {xTicks.map((tick) => {
97	            const x = scaleNumber(tick, domainStart, domainEnd, chartLeft, chartRight);
98	            return (
99	              <g key={tick}>
100	                <line
101	                  x1={x}
102	                  y1={chartTop}
103	                  x2={x}
104	                  y2={chartBottom}
105	                  stroke="rgba(139, 143, 163, 0.16)"
106	                />
107	                <text
108	                  x={x}
109	                  y={HEIGHT - 14}
110	                  fill="var(--color-text-muted)"
111	                  fontSize="11"
112	                  textAnchor="middle"
113	                >
