124	            y2={chartBottom}
125	            stroke="var(--color-border)"
126	          />
127	          <line
128	            x1={chartLeft}
129	            y1={chartTop}
130	            x2={chartLeft}
131	            y2={chartBottom}
132	            stroke="var(--color-border)"
133	          />
134	
135	          {series.map((outcome, outcomeIndex) => {
136	            const points = outcome.points.map((point) => ({
137	              x: scaleNumber(
138	                Date.parse(point.emittedAt),
139	                domainStart,
140	                domainEnd,
141	                chartLeft,
142	                chartRight,
