2	import { Link, useSearchParams } from "react-router-dom";
3	import { AccountPnlSection } from "@/features/analytics/AccountPnlSection";
4	import { AnalyticsFilters } from "@/features/analytics/AnalyticsFilters";
5	import { AnalyticsSummaryCards } from "@/features/analytics/AnalyticsSummaryCards";
6	import { PriceChart } from "@/features/analytics/PriceChart";
7	import { TraderLeaderboard } from "@/features/analytics/TraderLeaderboard";
8	import { VolumeChart } from "@/features/analytics/VolumeChart";
9	import { useSession } from "@/features/session/context";
10	import type { AnalyticsInterval, MarketSummary } from "@/lib/api/types";
11	import { useAccountPnl, useMarketAnalytics, useMarkets } from "@/lib/query/hooks";
12	import { ErrorMessage, LoadingPage } from "@/components/ui/Spinner";
13	
14	function isAnalyticsInterval(value: string | null): value is AnalyticsInterval {
15	  return value === "hour" || value === "day";
16	}
17	
18	function preferredMarket(markets: MarketSummary[]): MarketSummary | undefined {
19	  return markets.find((market) => market.status === "active") ?? markets[0];
20	}
21	
22	export default function Analytics() {
23	  const { session } = useSession();
24	  const marketsQuery = useMarkets();
25	  const pnlQuery = useAccountPnl(session.accountId);
26	  const [searchParams, setSearchParams] = useSearchParams();
27	
28	  const interval: AnalyticsInterval = isAnalyticsInterval(searchParams.get("interval")) ? (searchParams.get("interval") as AnalyticsInterval) : "day";
29	  const markets = marketsQuery.data?.markets ?? [];
30	  const selectedMarket = markets.find((market) => market.id === searchParams.get("market")) ?? preferredMarket(markets);
31	  const selectedMarketId = selectedMarket?.id ?? "";
32	  const analyticsQuery = useMarketAnalytics(selectedMarketId, {
33	    enabled: selectedMarketId.length > 0,
34	    interval,
35	  });
36	
37	  useEffect(() => {
38	    if (!selectedMarketId) {
39	      return;
40	    }
41	
42	    const next = new URLSearchParams(searchParams);
43	    let changed = false;
44	
45	    if (next.get("market") !== selectedMarketId) {
46	      next.set("market", selectedMarketId);
47	      changed = true;
48	    }
49	
50	    if (!isAnalyticsInterval(next.get("interval"))) {
51	      next.set("interval", interval);
52	      changed = true;
53	    }
54	
55	    if (changed) {
56	      setSearchParams(next, { replace: true });
57	    }
58	  }, [interval, searchParams, selectedMarketId, setSearchParams]);
59	
60	  if (marketsQuery.isLoading && markets.length === 0) {
61	    return <LoadingPage />;
62	  }
63	
64	  if (marketsQuery.error) {
65	    return <ErrorMessage message={marketsQuery.error instanceof Error ? marketsQuery.error.message : "Failed to load markets"} />;
66	  }
67	
68	  if (markets.length === 0) {
69	    return (
70	      <div style={emptyStateStyle}>
71	        No markets exist yet. Create a market before loading analytics.
72	        <div style={{ marginTop: "var(--space-sm)" }}>
73	          <Link to="/markets/new">Create a market</Link>
74	        </div>
75	      </div>
76	    );
77	  }
78	
79	  function updateParams(nextValues: { market?: string; interval?: AnalyticsInterval }) {
80	    const next = new URLSearchParams(searchParams);
81	    if (nextValues.market) {
82	      next.set("market", nextValues.market);
83	    }
84	    if (nextValues.interval) {
85	      next.set("interval", nextValues.interval);
86	    }
87	    setSearchParams(next);
88	  }
89	
